1	export type Cell = [number, number];
2	
3	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const survives = (isAlive: boolean, neighbors: number): boolean =>
6	  (isAlive && (neighbors === 2 || neighbors === 3)) ||
7	  (!isAlive && neighbors === 3);
8	
9	const OFFSETS: ReadonlyArray<[number, number]> = [
10	  [-1, -1], [-1, 0], [-1, 1],
11	  [ 0, -1],          [ 0, 1],
12	  [ 1, -1], [ 1, 0], [ 1, 1],
13	];
14	
15	const neighborsOf = ([x, y]: Cell): Cell[] =>
16	  OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
17	
18	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
19	  const liveKeys = new Set(liveCells.map(keyOf));
20	  const candidates = new Map<string, Cell>();
21	  const neighborCounts = new Map<string, number>();
22	
23	  for (const cell of liveCells.flatMap(neighborsOf)) {
24	    const k = keyOf(cell);
25	    candidates.set(k, cell);
26	    neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
27	  }
28	
29	  return [...candidates]
30	    .filter(([k]) => survives(liveKeys.has(k), neighborCounts.get(k) ?? 0))
31	    .map(([, cell]) => cell);
32	};
33

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells with only 1 neighbor each (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (still life) unchanged", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should transform vertical blinker to horizontal blinker", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(vertical);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(horizontal));
26	  });
27	  it("should create a new live cell via reproduction (dead cell with exactly 3 neighbors)", () => {
28	    const lShape: [number, number][] = [[0, 0], [1, 0], [0, 1]];
29	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
30	    const result = nextGeneration(lShape);
31	    expect(result).toHaveLength(4);
32	    expect(result).toEqual(expect.arrayContaining(expected));
33	  });
34	  it("should kill a cell with more than 3 neighbors (overpopulation)", () => {
35	    // Center (1,1) has 6 live neighbors → dies
36	    const input: [number, number][] = [
37	      [0, 0], [1, 0], [2, 0],
38	      [1, 1],
39	      [0, 2], [1, 2], [2, 2],
40	    ];
41	    const result = nextGeneration(input);
42	    expect(result).not.toContainEqual([1, 1]);
43	  });
44	  it("should handle negative coordinates", () => {
45	    const vertical: [number, number][] = [[-5, -1], [-5, 0], [-5, 1]];
46	    const horizontal: [number, number][] = [[-6, 0], [-5, 0], [-4, 0]];
47	    const result = nextGeneration(vertical);
48	    expect(result).toHaveLength(3);
49	    expect(result).toEqual(expect.arrayContaining(horizontal));
50	  });
51	});
